enum
{
  PROP_0,
  PROP_DRAWABLE,
  PROP_MODEL
};

typedef struct
{
  gboolean  update;
} PreviewSettings;


struct _GimpZoomPreview
{
  GimpScrolledPreview  parent_instance;

  GimpDrawable        *drawable;
  GimpZoomModel       *model;
  GdkRectangle         extents;
};


